import SwiftUI

/// All visual constants for Ordering/Edit Mode and the Song Editor.
/// Adjust these after testing on the actual iPad.
struct EditTheme {
    // MARK: Font sizes
    static let setlistNameSize: CGFloat = 13
    static let setlistDateSize: CGFloat = 11
    static let songTitleSize: CGFloat = 14
    static let songPreviewSize: CGFloat = 12
    static let reminderSize: CGFloat = 11
    static let editorTitleSize: CGFloat = 16

    // MARK: Colors
    static let primaryText = Color.primary
    static let secondaryText = Color.secondary
    static let reminderColor = Color(red: 1.0, green: 0.58, blue: 0.0)
    static let tacetText = Color.secondary
    static let accentColor = Color.accentColor
    static let destructiveColor = Color.red
}

import SwiftUI
/// All visual constants for Ordering/Edit Mode and the Song Editor. /// Adjust these after testing on the actual iPad. struct EditTheme { // MARK: Font sizes static let setlistNameSize: CGFloat = 13 static let setlistDateSize: CGFloat = 11 static let songTitleSize: CGFloat = 14 static let songPreviewSize: CGFloat = 12 static let reminderSize: CGFloat = 11 static let editorTitleSize: CGFloat = 16 static let rowNumberSize: CGFloat = 13 static let rowChevronSize: CGFloat = 11
// MARK: Colors static let primaryText = Color.primary static let secondaryText = Color.secondary static let reminderColor = Color(red: 1.0, green: 0.58, blue: 0.0) static let tacetText = Color.secondary static let accentColor = Color.accentColor static let destructiveColor = Color.red }

import SwiftUI
import SwiftData

struct SetlistDetailView: View {
    @Bindable var setlist: Setlist
    @Environment(\.modelContext) private var context

    @State private var showSongLibrary = false
    @State private var showTacetEdit = false
    @State private var editingEntry: SetlistEntry?
    @State private var showPerformance = false

    var body: some View {
        List {
            ForEach(setlist.sortedEntries) { entry in
                Group {
                    switch entry.itemType {
                    case .song:
                        SongEntryRow(entry: entry) {
                            editingEntry = entry
                        }
                    case .tacet:
                        TacetRow(entry: entry) {
                            editingEntry = entry
                        }
                        //.listRowBackground(Color.secondary.opacity(0.07))
                    }
                }
                .swipeActions(edge: .trailing) {
                    Button(role: .destructive) {
                        deleteEntry(entry)
                    } label: {
                        Label("Delete", systemImage: "trash")
                    }
                }
            }
            .onMove(perform: moveEntries)

            AddEntryRow(
                onAddSong: { showSongLibrary = true },
                onAddTacet: { showTacetEdit = true }
            )
            .listRowBackground(Color.clear)
            .listRowSeparator(.hidden)
        }
        .listStyle(.plain)
        .navigationTitle(setlist.name)
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .navigationBarLeading) {
                EditButton()
            }
            ToolbarItem(placement: .navigationBarTrailing) {
                Button {
                    showPerformance = true
                } label: {
                    Label("Perform", systemImage: "play.fill")
                }
                .buttonStyle(.borderedProminent)
            }
        }
        .sheet(isPresented: $showSongLibrary) {
            SongLibrarySheet(setlist: setlist)
        }
        .sheet(isPresented: $showTacetEdit) {
            TacetEditSheet(entry: nil, setlist: setlist)
        }
        .sheet(item: $editingEntry) { entry in
            switch entry.itemType {
            case .song:
                SongEditorSheet(song: entry.song!)
            case .tacet:
                TacetEditSheet(entry: entry, setlist: setlist)
            }
        }
        .fullScreenCover(isPresented: $showPerformance) {
            if #available(iOS 18.0, *) {
                PerformanceView(setlist: setlist)
            }
        }
    }

    private func moveEntries(from source: IndexSet, to destination: Int) {
        var sorted = setlist.sortedEntries
        sorted.move(fromOffsets: source, toOffset: destination)
        for (index, entry) in sorted.enumerated() {
            entry.order = index
        }
    }

    private func deleteEntry(_ entry: SetlistEntry) {
        setlist.entries.removeAll { $0.persistentModelID == entry.persistentModelID }
        context.delete(entry)
    }
}

import SwiftUI
import SwiftData

struct SetlistDetailView: View {
    @Bindable var setlist: Setlist
    @Environment(\.modelContext) private var context

    @State private var showSongLibrary = false
    @State private var showTacetEdit = false
    @State private var editingEntry: SetlistEntry?
    @State private var showPerformance = false

    var body: some View {
        List {
            // ── Setlist entries (reorderable + swipe-to-delete) ──────────────
            Section {
                ForEach(Array(setlist.sortedEntries.enumerated()), id: \.element.persistentModelID) { index, entry in
                    Group {
                        switch entry.itemType {
                        case .song:
                            SongEntryRow(entry: entry, position: index + 1) {
                                editingEntry = entry
                            }
                        case .tacet:
                            TacetRow(entry: entry, position: index + 1) {
                                editingEntry = entry
                            }
                        }
                    }
                    .swipeActions(edge: .trailing, allowsFullSwipe: true) {
                        Button(role: .destructive) {
                            deleteEntry(entry)
                        } label: {
                            Label("Delete", systemImage: "trash")
                        }
                    }
                }
                .onMove(perform: moveEntries)
            }

            // ── Add controls ─────────────────────────────────────────────────
            AddEntrySection(
                onAddSong: { showSongLibrary = true },
                onAddTacet: { showTacetEdit = true }
            )
        }
        .listStyle(.plain)
        .navigationTitle(setlist.name)
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .navigationBarLeading) {
                EditButton()
            }
            ToolbarItem(placement: .navigationBarTrailing) {
                Button {
                    showPerformance = true
                } label: {
                    Label("Perform", systemImage: "play.fill")
                }
                .buttonStyle(.borderedProminent)
            }
        }
        .sheet(isPresented: $showSongLibrary) {
            SongLibrarySheet(setlist: setlist)
        }
        .sheet(isPresented: $showTacetEdit) {
            TacetEditSheet(entry: nil, setlist: setlist)
        }
        .sheet(item: $editingEntry) { entry in
            switch entry.itemType {
            case .song:
                SongEditorSheet(song: entry.song!)
            case .tacet:
                TacetEditSheet(entry: entry, setlist: setlist)
            }
        }
        .fullScreenCover(isPresented: $showPerformance) {
            if #available(iOS 18.0, *) {
                PerformanceView(setlist: setlist)
            }
        }
    }

    private func moveEntries(from source: IndexSet, to destination: Int) {
        var sorted = setlist.sortedEntries
        sorted.move(fromOffsets: source, toOffset: destination)
        for (index, entry) in sorted.enumerated() {
            entry.order = index
        }
    }

    private func deleteEntry(_ entry: SetlistEntry) {
        setlist.entries.removeAll { $0.persistentModelID == entry.persistentModelID }
        context.delete(entry)
    }
}

import SwiftUI

struct SongEntryRow: View {
    let entry: SetlistEntry
    let onEdit: () -> Void

    private var song: Song { entry.song! }

    private var contentPreview: String {
        song.content
            .components(separatedBy: .newlines)
            .first(where: { !$0.trimmingCharacters(in: .whitespaces).isEmpty
                           && !$0.hasPrefix("#")
                           && !$0.hasPrefix("```") })
            ?? ""
    }

    var body: some View {
        Button(action: onEdit) {
            HStack(alignment: .top) {
                VStack(alignment: .leading, spacing: 2) {
                    HStack(spacing: 6) {
                        Text(song.title)
                            .font(.system(size: EditTheme.songTitleSize, weight: .semibold))
                            .foregroundStyle(EditTheme.primaryText)
                        if let reminder = song.reminder {
                            Text(reminder)
                                .font(.system(size: EditTheme.reminderSize, weight: .semibold))
                                .foregroundStyle(EditTheme.reminderColor)
                        }
                    }
                    if !contentPreview.isEmpty {
                        Text(contentPreview)
                            .font(.system(size: EditTheme.songPreviewSize))
                            .foregroundStyle(EditTheme.secondaryText)
                            .lineLimit(1)
                    }
                }
                Spacer()
            }
            .padding(.vertical, 4)
        }
        .buttonStyle(.plain)
    }
}

import SwiftUI

struct SongEntryRow: View {
    let entry: SetlistEntry
    let position: Int
    let onEdit: () -> Void

    private var song: Song { entry.song! }

    private var contentPreview: String {
        song.content
            .components(separatedBy: .newlines)
            .first(where: { !$0.trimmingCharacters(in: .whitespaces).isEmpty
                           && !$0.hasPrefix("#")
                           && !$0.hasPrefix("```") })
            ?? ""
    }

    var body: some View {
        HStack(alignment: .center, spacing: 12) {
            Text("\(position)")
                .font(.system(size: EditTheme.rowNumberSize, weight: .regular).monospacedDigit())
                .foregroundStyle(EditTheme.secondaryText)
                .frame(minWidth: 22, alignment: .trailing)

            VStack(alignment: .leading, spacing: 2) {
                HStack(spacing: 6) {
                    Text(song.title)
                        .font(.system(size: EditTheme.songTitleSize, weight: .semibold))
                        .foregroundStyle(EditTheme.primaryText)
                    if let reminder = song.reminder {
                        Text(reminder)
                            .font(.system(size: EditTheme.reminderSize, weight: .semibold))
                            .foregroundStyle(EditTheme.reminderColor)
                    }
                }
                if !contentPreview.isEmpty {
                    Text(contentPreview)
                        .font(.system(size: EditTheme.songPreviewSize))
                        .foregroundStyle(EditTheme.secondaryText)
                        .lineLimit(1)
                }
            }

            Spacer()

            Image(systemName: "chevron.right")
                .font(.system(size: EditTheme.rowChevronSize, weight: .semibold))
                .foregroundStyle(EditTheme.secondaryText.opacity(0.35))
        }
        .padding(.vertical, 4)
        .contentShape(Rectangle())
        .onTapGesture(perform: onEdit)
    }
}

import SwiftUI

struct TacetRow: View {
    let entry: SetlistEntry
    let onEdit: () -> Void

    private var tacet: Tacet { entry.tacet! }

    private var displayLabel: String {
        if let label = tacet.label, !label.isEmpty {
            return "— \(label) —"
        }
        return "— Tacet —"
    }

    var body: some View {
        Button(action: onEdit) {
            HStack {
                Text(displayLabel)
                    .font(.system(size: EditTheme.songPreviewSize))
                    .italic()
                    .foregroundStyle(EditTheme.tacetText)
                Spacer()
            }
            .padding(.vertical, 6)
        }
        .buttonStyle(.plain)
    }
}

import SwiftUI

